SELECT category, AVG(font_size) AS average_font_size
FROM passwords
GROUP BY category;

SELECT password, strength
FROM passwords
WHERE strength < 50;

SELECT password FROM passwords
INTERSECT
SELECT password FROM common_passwords;

SELECT password_id, password
FROM passwords
WHERE strength > (
    SELECT AVG(strength)
    FROM passwords
);

SELECT pc.password_id, pc.user_id, pc.check_date, pc.result, p.status
FROM password_checks pc
INNER JOIN passwords p ON pc.password_id = p.password_id;

SELECT password, UNICODE(password) AS PasswordUnicode 
FROM passwords 
WHERE strength = (SELECT MAX(strength) FROM passwords);

SELECT AVG(password_strength.strength_score) AS average_strength_score
FROM passwords
JOIN password_strength ON passwords.password_id = password_strength.password_id;

SELECT DISTINCT user_name
FROM users
INNER JOIN recommendations ON users.user_id = recommendations.user_id;

SELECT password
FROM passwords
WHERE password_id = 1;

SELECT categories.category_name, common_passwords.frequency
FROM categories
INNER JOIN common_passwords ON categories.category_name = common_passwords.category;

SELECT COUNT(*) 
FROM common_passwords
WHERE category = 'simple-alphanumeric';

SELECT password_id, password, status, category
FROM passwords
ORDER BY status, category;
